      httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
      httptransport.WithErrorEncoder(errorEncoder()),
    )...,
  )
}

func domainPriceToAPI(p llmcost.Price) api.LLMCostPrice {
  source := api.LLMCostPriceSourceSystem
  if p.Source == llmcost.PriceSourceManual { source = api.LLMCostPriceSourceManual }
  providerID := string(p.Provider)
  out := api.LLMCostPrice{
    Id: p.ID,
    Provider: api.LLMCostProvider{Id: providerID, Name: formatProviderName(providerID)},
    Model: api.LLMCostModel{Id: p.ModelID, Name: p.ModelName},
    Currency: p.Currency,
    Source: source,
    Pricing: domainPricingToAPI(p.Pricing),
  }
  return out
}

func domainPricingToAPI(p llmcost.ModelPricing) api.LLMCostModelPricing {
  out := api.LLMCostModelPricing{
    InputPerToken:  p.InputPerToken.String(),
    OutputPerToken: p.OutputPerToken.String(),
  }
  if p.CacheReadPerToken != nil { out.CacheReadPerToken = lo.ToPtr(p.CacheReadPerToken.String()) }
  if p.CacheWritePerToken != nil { out.CacheWritePerToken = lo.ToPtr(p.CacheWritePerToken.String()) }
  if p.ReasoningPerToken != nil { out.ReasoningPerToken = lo.ToPtr(p.ReasoningPerToken.String()) }
  return out
}

